INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('colonel-d0d1b9a2-moex-00108', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-110-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X3年1月1日給與30位員工每人1,500單位認股權。其條件為 員工必須自 X3 年 1 月 1 日起連續服務滿 3 年，且 X5 年底公司股價須大 於$40，始能既得。該認股權之存續期間6年、履約價格$35，給與日之股 票評估價值$35，但無法可靠估計所給與認股權之公允價值。假設X3年至 X6 年底，該方案在職人數分別為 28、26、24、22，股票評估價值分別為 $36、$37、$41、$43。X5 年底有 4 人執行該認股權（其中 2 人於隔年離 職），X6年初有5人執行該認股權。試問，甲公司X6年度應認列該方案 相關之薪資費用為何？', '["$(18,000)", "$0", "$45,000", "$60,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00109', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-110-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年初購入乙公司60%之普通股，成為乙公司之母公司。此外 ，甲公司於X1年9月1日購入丙公司36%之普通股，對丙公司具重大影 響力，而丙公司在X0年初就已取得丁公司25%股權，丁公司為丙公司之 關聯企業。乙公司 X1 年度出售毛利$2,000,000 之商品一批給丁公司，請 問甲公司將對乙公司股權投資採權益法處理時，應消除多少乙公司對丁公 司銷貨之未實現損益？', '["$0", "$36,000", "$108,000", "$144,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00110', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-110-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '下列何者應表達於綜合損益表中？', '["因精算損益而產生之確定福利計畫再衡量數", "公司收到採權益法投資之關聯企業所宣告並發放的現金股利", "公司因自建廠房而向銀行專案借款，於建造期間所需支付的利息", "存貨評價由原先採行之加權平均法變更為先進先出法而產生之追溯適 用累積影響數"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00111', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-110-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司 12 月舉行買 2 千送 5 百的年終感恩促銷活動，顧客於該月購買商 品每滿2千就獲得5百元之折價券一張，可於下月購物時直接折抵現金， 公司估計折價券之使用率達70%。請問公司此項促銷活動對毛利率與營業 利益率之可能產生影響方向為何？', '["毛利率下降、營業利益率下降", "毛利率上升、營業利益率上升", "毛利率不變、營業利益率上升", "毛利率上升、營業利益率不變"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00112', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-110-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司使用零售價法估算期末存貨，X1年相關資訊如下： 期初存貨（成本） $ 35,000 加價 $ 8,000 期初存貨（零售價） 52,500 加價取消 4,000 進貨（成本） 145,600 減價 5,000 進貨（零售價） 225,000 銷貨收入 240,000 若甲公司採先進先出法評價存貨，則X1年期末存貨成本為多少？', '["$23,417", "$23,725", "$23,841", "$24,190"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00113', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-110-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司與乙客戶於X1年12月1日簽訂一合約，合約內容如下表所示： 履約義務 分攤交易價格 收款方式 收入認列日 提供三個月資 銷售設備 $1,000 訊服務後一次 X1年12月31日 收取 簽約時預收一 即日起一年資 $12,000 半，餘款第六個 隨逐月提供服務認列 訊服務 （每月$1,000） 月一次收取 試問，甲公司於X1年相關財務報表應如何表達上述合約？', '["應認列應收帳款$1,000", "應認列合約資產$7,000", "應認列合約負債$4,000", "應認列收入$1,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00114', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-110-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司於 X8 年初以$150,000 購入乙公司普通股，另支付手續費$450，分 類為透過其他綜合損益按公允價值衡量股票投資。X8 年 12 月 31 日該批 股票公允價值為$200,000，X9 年 11 月 1 日甲公司將這些股票以$180,000 出售，則該股票投資對X9年度本期綜合損益總額之影響為：', '["增加$29,550", "減少$30,000", "減少$19,550", "減少$20,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00115', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-110-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '乙公司於 X2 年初承包長期建造合約，其合約義務為隨時間逐步履約者， 工程總價為$6,500,000，預計 3 年完工，且該合約之結果能合理衡量估計 。X2 年相關資料如下：估計總合約成本$4,500,000、當年投入工程成本 $2,520,000、工程進度請款金額$1,900,000與實際收款金額$1,500,000。X3 年相關資料如下：估計總合約成本$5,800,000、當年投入工程成本 $1,366,000、工程進度請款金額$3,000,000 與實際收款金額$2,500,000。若 該公司採成本比例法衡量履約義務完成程度，請問乙公司至 X3 年底關於 該合約之累積利潤為何？', '["$548,000", "$375,000", "$469,000", "$501,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00116', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-110-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年初成立，X1年度稅前淨利為$5,000,000，X1年底之應收利 息及應付利息分別為$20,000及$8,000，由於稅法規定利息收付必須以現金 收付為基礎，各年度稅率均為20%。該公司並無其他暫時性差異存在，所 有可減除之暫時性差異在未來很有可能有課稅所得可供此差異使用，請問 X1年底之應付所得稅為多少？', '["$994,400", "$997,600", "$1,000,000", "$1,002,400"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00117', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-110-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '乙公司持有丙公司股票，該投資於X2 年1 月1 日資產負債表列報「透過 損益按公允價值衡量之投資」$600,000與「透過損益按公允價值衡量之投 資評價調整」為$30,000（貸餘）。X2 年 7 月 1 日以每股$25 出售半數（ 15,000 股）之丙公司股票。X3 年 3 月 1 日以每股$12 再購買丙公司股票 3,000股。X2年底與X3年底丙公司股票每股公允價值分別為$23與$15。 請問X3年底「透過損益按公允價值衡量之投資評價調整」餘額為何？', '["$90,000", "$45,000", "$(33,000)", "$(66,000)"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:57+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL)
